#!/usr/bin/env node
// scripts/docs/generate-playbook-index.mjs
//
// Scan `docs/playbooks/*.md`, extract each playbook's `**Trigger:**` line,
// and generate `docs/playbooks/INDEX.md` вЂ” a lookup table В«phrase в†’ playbookВ».
//
// Right now agents and humans have to grep or read `README.md` to figure out
// which playbook matches a request. An auto-generated index gives O(1) lookup
// and keeps itself honest: if a playbook changes its Trigger, the INDEX.md
// diff surfaces in the same PR.
//
// Usage:
//   node scripts/docs/generate-playbook-index.mjs            # write INDEX.md
//   node scripts/docs/generate-playbook-index.mjs --check    # CI mode: fail if diff
//
// Exit code 1 on --check diff or I/O error.

import { readFileSync, readdirSync, writeFileSync, existsSync } from "node:fs";
import { resolve, dirname, join } from "node:path";
import { fileURLToPath } from "node:url";

const __filename = fileURLToPath(import.meta.url);
const __dirname = dirname(__filename);
const REPO_ROOT = resolve(__dirname, "../..");
const PLAYBOOKS_DIR = resolve(REPO_ROOT, "docs/playbooks");
const INDEX_PATH = join(PLAYBOOKS_DIR, "INDEX.md");

// Files that are NOT playbooks and should be skipped from the index.
const SKIP_FILES = new Set([
  "README.md",
  "INDEX.md",
  "_TEMPLATE-decision-tree.md",
]);

const RE_TRIGGER_LINE = /^\s*\*\*Trigger:\*\*\s*(.+?)\s*$/m;
const RE_H1 = /^#\s+(?:Playbook:\s*)?(.+?)\s*$/m;
const RE_DECISION_TREE_MARK = /рџЊі/;

// в”Ђв”Ђ Pure helpers (exported for tests) в”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђ

/**
 * Extract `{ title, trigger, isDecisionTree }` from a playbook's markdown body.
 * Returns null if no trigger line is found (not a valid playbook).
 */
export function extractPlaybookMeta(content) {
  const titleMatch = RE_H1.exec(content);
  const triggerMatch = RE_TRIGGER_LINE.exec(content);
  if (!triggerMatch) return null;
  const title = titleMatch ? titleMatch[1].trim() : null;
  const trigger = triggerMatch[1].replace(/\s+/g, " ").trim();
  const isDecisionTree = RE_DECISION_TREE_MARK.test(content.slice(0, 2000));
  return { title, trigger, isDecisionTree };
}

/**
 * Escape a string so it can safely go inside a markdown table cell.
 * - Pipe chars break the row: escape with `\|`.
 * - Literal newlines break the row: collapse to spaces.
 */
export function escapeTableCell(s) {
  return s.replace(/\|/g, "\\|").replace(/\r?\n/g, " ").trim();
}

/**
 * Build the full INDEX.md body from a list of { file, title, trigger, isDecisionTree }.
 * Sorts by filename for stable output.
 */
export function renderIndex(entries, { today = todayISO() } = {}) {
  const sorted = [...entries].sort((a, b) => a.file.localeCompare(b.file));
  const rows = sorted
    .map((e) => {
      const link = `[\`${e.file}\`](./${e.file})`;
      const tree = e.isDecisionTree ? "рџЊі " : "";
      const title = e.title
        ? `${tree}${e.title}`
        : `${tree}${e.file.replace(/\.md$/, "")}`;
      return `| ${link} | ${escapeTableCell(title)} | ${escapeTableCell(e.trigger)} |`;
    })
    .join("\n");

  return [
    "# Playbooks вЂ” Trigger Index",
    "",
    `> **Last validated:** ${today} by @devin-ai. **Next review:** ${addDays(today, 90)}.`,
    "> **Status:** Active",
    "",
    "> **Auto-generated** by `scripts/docs/generate-playbook-index.mjs`.",
    "> Do NOT edit this file by hand вЂ” regenerate with `pnpm docs:gen-playbook-index`.",
    "> Checked in CI via `pnpm docs:check-playbook-index`.",
    "",
    "Lookup table for agents and humans: find the playbook that matches a user request by its **Trigger** phrase.",
    "",
    "| Playbook | Title | Trigger |",
    "| -------- | ----- | ------- |",
    rows,
    "",
  ].join("\n");
}

/** Add `days` calendar days to an ISO date string. */
export function addDays(isoDate, days) {
  const d = new Date(isoDate + "T00:00:00Z");
  d.setUTCDate(d.getUTCDate() + days);
  return d.toISOString().slice(0, 10);
}

/** Today in YYYY-MM-DD UTC. */
export function todayISO() {
  return new Date().toISOString().slice(0, 10);
}

/**
 * Normalise a rendered index for equality comparison in `--check` mode.
 * Ignores:
 *   - daily freshness dates (Last validated / Next review)
 *   - Prettier table-column padding (the on-disk file is re-flowed by the
 *     repo's Prettier config, our generator emits compact tables)
 *   - leading / trailing whitespace and blank-line differences
 */
export function normaliseForCompare(s) {
  return s
    .replace(
      /Last validated:\*\* \d{4}-\d{2}-\d{2}[^\n]*/g,
      "Last validated:**",
    )
    .replace(/Next review:\*\* \d{4}-\d{2}-\d{2}[^\n]*/g, "Next review:**")
    .split(/\r?\n/)
    .map((line) => {
      // Collapse internal whitespace runs in table rows so Prettier's padding
      // doesn't create a spurious diff; other lines keep their shape.
      if (line.trimStart().startsWith("|")) {
        return line
          .replace(/-{2,}/g, "-") // `-----` в†’ `-`
          .replace(/\s+/g, " ")
          .trim();
      }
      return line.trimEnd();
    })
    .filter((line, i, arr) => !(line === "" && arr[i - 1] === ""))
    .join("\n")
    .trim();
}

/**
 * Scan the playbooks directory and return extracted metadata for each file.
 * { file, title, trigger, isDecisionTree }
 */
export function collectEntries(dir = PLAYBOOKS_DIR) {
  const files = readdirSync(dir)
    .filter((f) => f.endsWith(".md"))
    .filter((f) => !SKIP_FILES.has(f));

  const out = [];
  for (const file of files) {
    const content = readFileSync(join(dir, file), "utf8");
    const meta = extractPlaybookMeta(content);
    if (!meta) {
      console.warn(
        `[WARN] No **Trigger:** line in docs/playbooks/${file} вЂ” skipped`,
      );
      continue;
    }
    out.push({ file, ...meta });
  }
  return out;
}

// в”Ђв”Ђ Main в”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђ

function main() {
  const checkMode = process.argv.includes("--check");
  const entries = collectEntries();
  const body = renderIndex(entries);

  if (checkMode) {
    if (!existsSync(INDEX_PATH)) {
      console.error(
        `вќЊ docs/playbooks/INDEX.md does not exist. Run: pnpm docs:gen-playbook-index`,
      );
      process.exit(1);
    }
    const existing = readFileSync(INDEX_PATH, "utf8");
    if (normaliseForCompare(existing) !== normaliseForCompare(body)) {
      console.error(
        `вќЊ docs/playbooks/INDEX.md is out of date. Run: pnpm docs:gen-playbook-index`,
      );
      process.exit(1);
    }
    console.log(
      `вњ… docs/playbooks/INDEX.md is up to date (${entries.length} playbooks).`,
    );
    return;
  }

  writeFileSync(INDEX_PATH, body);
  console.log(`вњ…Wrote docs/playbooks/INDEX.md (${entries.length} playbooks).`);
}

const isMain =
  process.argv[1] &&
  resolve(process.argv[1]) === resolve(fileURLToPath(import.meta.url));
if (isMain) main();
